#include <bits/stdc++.h>
using namespace std;;
#define int long long

int n, m, c[500005], a[500005], t[500005];

int lowbit(int x)
{
    return x & -x;
}

void add(int x, int k)
{
    for(; x <= n; x += lowbit(x))
        c[x] += k;
}

int getsum(int x)
{
    int sum = 0;
    for(; x; x -= lowbit(x))
        sum += c[x];
    return sum;
}



signed main()
{
    cin >> n;
    for(int i = 1; i <= n; i++)
        cin >> a[i];
    for (int i = 1; i <= n; ++i)  
        t[i] = a[i];
    sort(t + 1, t + n + 1);                         
    int len = unique(t + 1, t + n + 1) - (t + 1);  
    for (int i = 1; i <= n; ++i)                              
        a[i] = lower_bound(t + 1, t + len + 1, a[i]) - t;
    int ans = 0;
    for(int i = 1; i <= n; i++)
    {
        ans += getsum(n) - getsum(a[i]);
        add(a[i], 1);
    }
    cout << ans;
    return 0;
}
